import { z } from 'zod';
import DOMPurify from 'isomorphic-dompurify';

// Sanitization utilities
export function sanitizeHTML(input: string | null): string | null {
  if (!input) return null;
  return DOMPurify.sanitize(input, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'code', 'pre'],
    ALLOWED_ATTR: ['href']
  });
}

export function validateURL(url: string): string {
  try {
    const parsed = new URL(url);
    // Only allow GitHub URLs and well-known CDNs
    if (parsed.protocol === 'https:' && 
        (parsed.hostname.endsWith('github.com') || 
         parsed.hostname.endsWith('githubusercontent.com') ||
         parsed.hostname.endsWith('gravatar.com'))) {
      return url;
    }
    throw new Error('Disallowed URL');
  } catch {
    return 'https://github.com'; // Safe fallback
  }
}

// Validation schemas
export const reviewBodySchema = z.string().max(65535).nullable().transform(sanitizeHTML);
export const commentBodySchema = z.string().max(65535).nullable().transform(sanitizeHTML);
export const htmlUrlSchema = z.string().url().max(2048).transform(validateURL);
export const avatarUrlSchema = z.string().url().max(2048).transform(validateURL);
export const filePathSchema = z.string().max(4096).regex(/^[a-zA-Z0-9._/-]+$/);
```

