```typescript
import { arcjet } from '@/lib/arcjet';
import { NextRequest } from 'next/server';

export async function POST(request: NextRequest): Promise<Response> {
  log.info('[webhook/github] Received webhook request');

  // Rate limit by GitHub installation ID (extracted from signature verification)
  // Allow 100 events per 10 seconds per installation
  const aj = await arcjet.protect(request, {
    requested: 1,
    characteristics: [
      // Use GitHub signature header as fingerprint (installation-specific)
      request.headers.get('X-Hub-Signature-256') || 'anonymous'
    ]
  });

  if (aj.denied) {
    log.warn('[webhook/github] Rate limit exceeded', {
      reason: aj.reason,
      fingerprint: request.headers.get('X-Hub-Signature-256')?.substring(0, 20)
    });
    return NextResponse.json(
      { message: 'Rate limit exceeded', ok: false },
      { status: 429 }
    );
  }

  if (!isGitHubConfigured()) {
    // ... rest of handler
  }
}
```

2. Add per-repository rate limiting for comment/review handlers:
```typescript
// In webhook-service.ts
export async function checkRepositoryRateLimit(
  repositoryId: number,
  eventType: string
): Promise<boolean> {
  // Use Redis or in-memory cache (e.g., node-cache) for rate limiting
  const cacheKey = `webhook:ratelimit:${repositoryId}:${eventType}`;

  // Allow 50 events per minute per repository per event type
  const limit = 50;
  const windowMs = 60_000;

  // Implement sliding window rate limit
  // (pseudo-code - actual implementation depends on cache provider)
  const count = await cache.increment(cacheKey);
  if (count === 1) {
    await cache.expire(cacheKey, windowMs / 1000);
  }

  return count <= limit;
}
```

