1. Create data sanitization utility for workstream events:
```typescript
// event-data-sanitizer.ts
import { log } from '@repo/observability/log';

/**
 * Sanitize sensitive content before storing in workstream events.
 * Truncates long content and removes potentially sensitive details.
 */
export function sanitizeEventData(data: Record<string, unknown>): Record<string, unknown> {
  const sanitized = { ...data };

  // Truncate long text fields to prevent excessive storage and data leakage
  const MAX_BODY_LENGTH = 500;
  const MAX_TITLE_LENGTH = 200;

  if (typeof sanitized.reviewBody === 'string') {
    sanitized.reviewBody = truncateWithEllipsis(sanitized.reviewBody, MAX_BODY_LENGTH);
  }

  if (typeof sanitized.commentBody === 'string') {
    sanitized.commentBody = truncateWithEllipsis(sanitized.commentBody, MAX_BODY_LENGTH);
  }

  if (typeof sanitized.prTitle === 'string') {
    sanitized.prTitle = truncateWithEllipsis(sanitized.prTitle, MAX_TITLE_LENGTH);
  }

  // Remove internal file paths from comment events (only store filename)
  if (typeof sanitized.commentPath === 'string') {
    const parts = sanitized.commentPath.split('/');
    sanitized.commentPath = parts[parts.length - 1]; // Only store filename
  }

  return sanitized;
}

function truncateWithEllipsis(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text;
  return text.substring(0, maxLength - 3) + '...';
}

/**
 * Check if repository is owned by the organization.
 * Used to determine if full event data should be stored.
 */
export async function isOrgOwnedRepository(
  repositoryId: number,
  organizationId: string
): Promise<boolean> {
  const repo = await withDb((db) =>
    db.repository.findFirst({
      where: {
        githubId: repositoryId,
        project: { organizationId }
      },
      select: { id: true }
    })
  );
  return repo !== null;
}
```

